<script setup lang="ts">
import { useSeoMeta } from "nuxt/app";
import { ref, onMounted, onBeforeUnmount } from "vue";

useSeoMeta({
  title: "MentorSpace | Nurturing Growth Across Kenya",
  description:
    "MentorSpace empowers youth, widows, and underserved communities across Kenya through mentorship, skills development, climate action, and sustainable livelihoods.",
  ogTitle: "MentorSpace | Nurturing Growth Across Kenya",
  ogDescription:
    "Empowering youth, widows, and underserved communities across Kenya through mentorship, skills development, and climate action.",
  ogImage: "/mentorspace-logo.svg",
});

interface Badge {
  label: string;
  bg: string;
  text: string;
}

interface Avatar {
  image?: string;
  angle: number;
  badge?: Badge;
}

interface Orbit {
  size: number;
  radius: number;
  top: string;
  left: string;
  duration: number;
  direction: "normal" | "reverse";
  avatars: Avatar[];
}

const orbits: Orbit[] = [
  {
    size: 2000,
    radius: 1000,
    top: "-70%",
    left: "-2.5rem",
    duration: 120,
    direction: "normal",
    avatars: [
      { angle: 20, image: "/img-1.svg" },
      {
        angle: 65,
        badge: { label: "Widow Empowerment", bg: "#F5EDFB", text: "#6B21A8" },
      },
      { angle: 110, image: "/img-2.svg" },
      { angle: 200, image: "/img-3.svg" },
      { angle: 310, image: "/img-4.svg" },
    ],
  },

  {
    size: 1700,
    radius: 850,
    top: "-40%",
    left: "5%",
    duration: 90,
    direction: "reverse",
    avatars: [
      { angle: 50, image: "/img-5.svg" },
      {
        angle: 100,
        badge: { label: "Youth Employability", bg: "#EAF2FB", text: "#1E40AF" },
      },
      { angle: 150, image: "/img-6.svg" },
      { angle: 250, image: "/img-7.svg" },
      { angle: 340, image: "/img-8.svg" },
    ],
  },

  {
    size: 1400,
    radius: 700,
    top: "-10%",
    left: "12%",
    duration: 70,
    direction: "normal",
    avatars: [
      { angle: 10, image: "/img-9.svg" },
      {
        angle: 55,
        badge: {
          label: "Youth Empowerment through IT",
          bg: "#EAFAF1",
          text: "#0F766E",
        },
      },
      { angle: 90, image: "/img-10.svg" },
      { angle: 170, image: "/img-11.svg" },
      {
        angle: 215,
        badge: { label: "Robotics", bg: "#FBECEC", text: "#B91C1C" },
      },
      { angle: 260, image: "/img-12.svg" },
      { angle: 340, image: "/img-13.svg" },
    ],
  },

  {
    size: 1100,
    radius: 550,
    top: "20%",
    left: "19%",
    duration: 50,
    direction: "reverse",
    avatars: [
      {
        angle: 45,
        image: "/img-14.svg",
      },
      {
        angle: 75,
        badge: { label: "Innovation", bg: "#EAFAF1", text: "#14532D" },
      },
      {
        angle: 200,
        badge: { label: "Education", bg: "#FAF4EA", text: "#D68A19" },
      },
      {
        angle: 105,
        image: "/img-15.svg",
      },
      { angle: 225, image: "/img-16.svg" },
      { angle: 315, image: "/img-17.svg" },
    ],
  },
];

/* Fluid orbit scaling: uniform scale vs a 1440px reference, clamped to 0.6–1. */
const ORBIT_REFERENCE_WIDTH = 1440;
const orbitScale = ref(1);

function updateOrbitScale() {
  const ratio = window.innerWidth / ORBIT_REFERENCE_WIDTH;
  orbitScale.value = Math.min(1, Math.max(0.6, ratio));
}

onMounted(() => {
  updateOrbitScale();
  window.addEventListener("resize", updateOrbitScale, { passive: true });
});

onBeforeUnmount(() => {
  window.removeEventListener("resize", updateOrbitScale);
});
</script>

<style scoped>
/* Orbit layer: fills the hero, scales the concentric rings as one unit (transform bound to orbitScale). */
.orbit-layer {
  position: absolute;
  inset: 0;
  z-index: 10;
  pointer-events: none;
  transform-origin: center;
  transition: transform 0.2s ease-out;
}

.orbit {
  animation-name: orbit;
  animation-timing-function: linear;
  animation-iteration-count: infinite;
}

.avatar {
  animation-name: orbit;
  animation-timing-function: linear;
  animation-iteration-count: infinite;
}

@keyframes orbit {
  from {
    transform: rotate(0deg);
  }

  to {
    transform: rotate(360deg);
  }
}

@media (prefers-reduced-motion: reduce) {
  .orbit,
  .avatar {
